Question: How many consecutive days did the average duration in pa_reports across all users increase, starting from 2022-06-15?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_avg AS (
    SELECT DATE(record_ts) AS report_date, AVG(duration) AS avg_duration
    FROM pa_reports
    WHERE record_ts >= '2022-06-15'
    GROUP BY report_date
),
consecutive_days AS (
    SELECT report_date, 
           @prev_avg := IF(@prev_avg IS NULL, avg_duration, @prev_avg) AS prev_avg,
           @prev_avg := avg_duration AS current_avg,
           @is_increasing := IF(avg_duration > @prev_avg, 1, 0) AS is_increasing,
           @count := IF(@is_increasing = 1, @count + 1, 1) AS streak
    FROM daily_avg, (SELECT @prev_avg := NULL, @count := 0, @is_increasing := 0) AS vars
    ORDER BY report_date
)
SELECT MAX(streak) AS consecutive_increase_days
FROM consecutive_days;

